import test from 'node:test';
import assert from 'node:assert/strict';

import { normalizeObservation } from '../src/observation.mjs';
import { summarizeMetric } from '../src/daily-rollup.mjs';

test('an unavailable sensor value remains missing during normalization', () => {
  assert.deepEqual(
    normalizeObservation({
      sensorId: 'flow-1',
      metric: 'flow',
      value: null,
      unit: 'L/s'
    }),
    {
      sensorId: 'flow-1',
      metric: 'flow',
      value: null,
      unit: 'L/s'
    }
  );
});

test('a measured zero participates in metric statistics', () => {
  assert.deepEqual(
    summarizeMetric(
      [
        { sensorId: 'flow-1', metric: 'flow', value: 0 },
        { sensorId: 'flow-2', metric: 'flow', value: 4 },
        { sensorId: 'flow-3', metric: 'flow', value: null }
      ],
      'flow'
    ),
    {
      metric: 'flow',
      count: 2,
      minimum: 0,
      maximum: 4,
      average: 2
    }
  );
});
